import i18n from 'i18next'
import { initReactI18next } from 'react-i18next'
import HttpBackend from 'i18next-http-backend'
import LanguageDetector from 'i18next-browser-languagedetector'

i18n
    .use(HttpBackend) // завантаження з public/locales
    .use(LanguageDetector) // визначення мови користувача
    .use(initReactI18next) // інтеграція з React
    .init({
        fallbackLng: 'en',
        debug: true,
        interpolation: {
            escapeValue: false, // React сам екранує XSS
        },
        backend: {
            loadPath: '/locales/{{lng}}/{{ns}}.json', // шлях до перекладів
        },
        react: {
            useSuspense: true, // дозволяє лоадінг при очікуванні
        },
    })

export default i18n
